/**
 * Notification model — types for the event-driven notification system.
 *
 * Architecture: All notifications flow through the EventBus. When a domain
 * event occurs (e.g., order:created), the NotificationService receives it,
 * builds a NotificationPayload, and dispatches it through registered
 * NotificationAdapters (email, webhook, in-app, etc.).
 *
 * Constraints:
 * - All notification delivery MUST go through a NotificationAdapter.
 * - All adapters MUST implement the NotificationAdapter interface.
 * - NotificationType must be extended here when adding new notification kinds.
 * - NotificationChannel must be extended here when adding new delivery channels.
 */

/**
 * The kind of notification being sent. Extend this union to add new types.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * The delivery channel for a notification. Each channel has a corresponding adapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in_app';

/**
 * Payload passed to a NotificationAdapter for delivery.
 */
export interface NotificationPayload {
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  channel: NotificationChannel;
  error?: string;
}

/**
 * Stored record of a notification that was dispatched.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  status: 'sent' | 'failed';
  sentAt: Date;
  error?: string;
  metadata?: Record<string, unknown>;
}

/**
 * Base interface for all notification adapters.
 *
 * CONSTRAINT: Every notification delivery channel (email, webhook, in-app, SMS,
 * etc.) MUST implement this interface. The NotificationService dispatches
 * payloads to all registered adapters — it does not know or care how delivery
 * works internally.
 *
 * To add a new channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create a new adapter file in src/adapters/ implementing this interface
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter delivers to (must be unique per adapter). */
  readonly channel: NotificationChannel;

  /**
   * Send a notification payload through this channel.
   * Must return a NotificationResult indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails instead of sending them.
 * Replace the send() internals with a real email provider (e.g., SendGrid,
 * SES, SMTP) for production use. The interface contract remains the same.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ to: string; subject: string; body: string; sentAt: Date }> = [];

  /**
   * Send a notification payload as an email.
   * Stub: stores the email in memory and returns success.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    // Stub: store in memory instead of actually sending
    this.sentEmails.push({
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    });

    return {
      success: true,
      channel: this.channel,
    };
  }

  /**
   * Get all sent emails (for testing and debugging).
   */
  getSentEmails(): Array<{ to: string; subject: string; body: string; sentAt: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — event-driven notification dispatch.
 *
 * ARCHITECTURE:
 * - Subscribes to domain events via EventBus (the ONLY input mechanism).
 * - Maps each event to a NotificationPayload.
 * - Dispatches payloads through all registered NotificationAdapters.
 * - Stores a record of every notification attempt.
 *
 * CONSTRAINTS:
 * 1. All notifications MUST originate from EventBus events. No direct calls.
 * 2. All delivery MUST go through NotificationAdapter implementations.
 * 3. New event→notification mappings go in registerHandlers().
 * 4. New delivery channels are added by implementing NotificationAdapter and
 *    calling registerAdapter().
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: NotificationAdapter[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for delivery.
   * Multiple adapters can be registered — each notification is sent through all of them.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter: ${adapter.channel}`);
    this.adapters.push(adapter);
  }

  /**
   * Subscribe to domain events that should trigger notifications.
   * Add new event→notification mappings here.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatch({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.dispatch({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Dispatch a notification payload through all registered adapters.
   * If no adapters are registered, stores the notification with channel 'email' as a fallback record.
   */
  private async dispatch(payload: NotificationPayload): Promise<void> {
    if (this.adapters.length === 0) {
      // No adapters registered — store as in-memory record for backward compatibility
      this.storeNotification(payload, 'email', true);
      return;
    }

    for (const adapter of this.adapters) {
      const result = await adapter.send(payload);
      this.storeNotification(payload, adapter.channel, result.success, result.error);
    }
  }

  /**
   * Store a notification record.
   */
  private storeNotification(
    payload: NotificationPayload,
    channel: Notification['channel'],
    success: boolean,
    error?: string,
  ): void {
    const notification: Notification = {
      id: generateNotificationId(),
      type: payload.type,
      channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      status: success ? 'sent' : 'failed',
      sentAt: new Date(),
      error,
      metadata: payload.metadata,
    };
    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} [${channel}] to ${payload.recipient}: ${notification.status}`);
  }

  /**
   * Get all notification records.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications filtered by type.
   */
  getNotificationsByType(type: NotificationType): Notification[] {
    return this.notifications.filter((n) => n.type === type);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

